import {useEffect, useState} from "react";
import UserService from "../services/user.service";
import EventBus from "../common/EventBus";
import {Form, Link} from "react-router-dom";
import Input from "react-validation/src/components/input";

const BoardAdmin = () => {
    const [content, setContent] = useState("");

    useEffect(() => {
        UserService.getAdminBoard().then(
            (response) => {
                setContent(response.data);
            },
            (error) => {
                const _content = (error.response && error.response.data && error.response.data.message) || error.message || error.toString();
                setContent(_content);
                if (error.response && error.response.status === 401) {
                    EventBus.dispatch("logout");
                }
            }
        );
    }, []);

    return (
        <div className="container">
            <header className="jumbotron">
                <h3>{content}</h3>
            </header>
            <div className="container bg-dark p-5">
            <span> <Link to="/" className="text-decoration-none">Trang chủ </Link>
                <i className="bi bi-chevron-double-right"></i>
                <span className="text-warning"> Đăng nhập</span>
            </span>
                <Form className="container p-4">
                    <h2 className="text-warning text-center">Đăng nhập</h2>
                    <div className="mb-3 mt-3">
                        <label htmlFor="email">Email:</label>
                        <Input
                            type="email"
                            className="form-control"
                            id="email"
                            placeholder="Enter email"
                            name="email"
                        />
                    </div>
                    <div className="mb-3">
                        <label htmlFor="pwd">Mật khẩu:</label>
                        <Input
                            type="password"
                            className="form-control"
                            id="pwd"
                            placeholder="Enter password"
                            name="password"
                            value={password}
                            onChange={onChangePassword}
                            validations={[required, validatePassword]}/>
                    </div>
                    <div className="form-check mb-3 text-end">
                        <label className="form-check-label me-3">
                            <Link className="text-decoration-none text-warning" to="/repassword">Quên mật khẩu </Link>
                        </label>
                        <label className="form-check-label">
                            <Link className="text-decoration-none text-warning" to="/register"> Đăng ký</Link>
                        </label>
                    </div>
                    <button disabled={loading} type="submit" className="btn btn-outline-warning form-control mb-3">
                        {loading && (
                            <span className="spinner-border spinner-border-sm"></span>
                        )}
                        <span>Đăng nhập</span>
                    </button>
                    <button type="submit" className="btn btn-outline-danger form-control">Đăng nhập bằng tài khoản
                        google
                    </button>
                    {message && (
                        <div className="form-group">
                            <div className="alert alert-danger" role="alert">
                                {message}
                            </div>
                        </div>
                    )}
                    <CheckButton style={{display: "none"}} ref={checkBtn}/>
                </Form>
            </div>
        </div>
    );
};

export default BoardAdmin;
